import * as React from 'react';
import NativeInput from '../shared/components/Input';
import type { StyleProps, StylexProps } from '../util/types';
import type { UsePinInputFieldProps, PinInputFieldRef } from './usePinInput';
import { usePinInputField } from './usePinInput';

/**
 * @docgen
 */
export interface PinInputFieldProps extends UsePinInputFieldProps, StyleProps, StylexProps {}

export const PinInputField = React.forwardRef<PinInputFieldRef, PinInputFieldProps>((props, ref) => {
  const { inputProps } = usePinInputField(props, ref);
  return <NativeInput {...inputProps} />;
});
